  col += 0.6 * exp(-sr3 * 22.0) * vec3(0.9, 0.95, 1.0);
  col += 0.12 * exp(-abs(sp3.x)*55.0) * exp(-sr3*3.0) * vec3(0.8,0.9,1.0);
  col += 0.12 * exp(-abs(sp3.y)*55.0) * exp(-sr3*3.0) * vec3(0.8,0.9,1.0);
